// pages/image-preview/image-preview.js
const imageConfig = require('../../utils/image-config.js')
const { getSystemInfo } = require('../../utils/system.js')

const SWIPE_CLOSE_THRESHOLD = 120
const SWIPE_MASK_DIVISOR = 520
const SWIPE_NAV_FADE_DISTANCE = 180

Page({
  data: {
    imageList: [],
    currentIndex: 0,
    title: '',
    showActionSheet: false,
    currentImage: '',
    statusBarHeight: 44,
    folderPath: '',
    showViewer: false,
    viewerUrls: [],
    viewerScale: 1,
    viewerTranslateX: 0,
    viewerTranslateY: 0,
    viewerSwipeY: 0,
    viewerMaskOpacity: 1,
    viewerNavOpacity: 1,
    viewerTransition: false,
    viewerDisableSwiper: false,
    directPreviewMode: false
  },

  onLoad(options) {
    const folder = decodeURIComponent(options.folder || '')
    const title = decodeURIComponent(options.title || '图片预览')

    const systemInfo = getSystemInfo()
    const statusBarHeight = systemInfo.statusBarHeight || 44

    const pages = typeof getCurrentPages === 'function' ? getCurrentPages() : []
    this.setData({
      title,
      statusBarHeight,
      isDirectEntry: pages.length <= 1,
      folderPath: folder
    })

    const directImagesRaw = decodeURIComponent(options.images || '')
    const startIndex = Math.max(0, Number(options.index || 0))

    if (directImagesRaw) {
      let directImages = []
      try {
        directImages = JSON.parse(directImagesRaw)
      } catch (err) {}

      const normalized = (Array.isArray(directImages) ? directImages : [])
        .map((url) => this.normalizeImageUrl(url))
        .filter(Boolean)

      if (normalized.length) {
        const safeIndex = Math.min(startIndex, normalized.length - 1)
        const currentUrl = normalized[safeIndex]
        this.setData({
          imageList: normalized,
          viewerUrls: currentUrl ? [currentUrl] : [],
          currentIndex: 0,
          showViewer: !!currentUrl,
          directPreviewMode: true
        })
        return
      }
    }

    this.loadImages(folder)
  },

  /**
   * 返回按钮兜底逻辑：
   * 1) 正常导航栈（>1 页）→ navigateBack
   * 2) 通过分享卡片冷启动进入（栈只有 1 页）→ switchTab 到「首页」TabBar
   * 3) 极端情况下 switchTab 仍失败 → reLaunch 兜底
   * 这样无论从哪种入口进来，左上角返回按钮都不会出现「无反应」。
   */
  goBack() {
    const FALLBACK_TAB = '/pages/index/index'
    const pages = typeof getCurrentPages === 'function' ? getCurrentPages() : []

    // wx.reLaunch 不支持 tabBar 页面，所以兜底链用 setTimeout + 再试 switchTab 覆盖
    // 极端的 tabBar 未初始化场景，确保分享冷启动时返回按钮不会"无反应"
    const retrySwitch = () => {
      setTimeout(() => {
        wx.switchTab({
          url: FALLBACK_TAB,
          fail: () => {
            try { wx.showToast({ title: '返回失败，请重启小程序', icon: 'none' }) } catch (_) {}
          }
        })
      }, 50)
    }

    if (pages.length > 1) {
      wx.navigateBack({
        fail: () => {
          wx.switchTab({ url: FALLBACK_TAB, fail: retrySwitch })
        }
      })
      return
    }
    wx.switchTab({ url: FALLBACK_TAB, fail: retrySwitch })
  },

  loadImages(folderPath) {
    const imageList = []

    try {
      const config = imageConfig[folderPath]

      if (config && config.images && Array.isArray(config.images)) {
        config.images.forEach(img => {
          if (img.startsWith('http://') || img.startsWith('https://')) {
            imageList.push(img)
          } else if (img.startsWith('/')) {
            imageList.push(img)
          } else {
            let imagePath = `${folderPath}/${img}`.replace(/\\/g, '/')
            if (!imagePath.startsWith('/')) {
              imagePath = `/${imagePath}`
            }
            imageList.push(imagePath)
          }
        })
      }
    } catch (e) {
    }

    this.setData({ imageList })
  },

  previewImage(e) {
    const index = Number(e.currentTarget.dataset.index || 0)
    const urls = (this.data.imageList || []).map((url) => this.normalizeImageUrl(url)).filter(Boolean)
    if (urls.length === 0) return

    const safeIndex = Math.max(0, Math.min(index, urls.length - 1))
    const currentUrl = urls[safeIndex]

    this.resetViewerGestureState(true)
    this.setData({
      viewerUrls: currentUrl ? [currentUrl] : [],
      currentIndex: 0,
      showViewer: !!currentUrl
    })
  },

  closeViewer() {
    this.resetViewerGestureState(false)

    if (this.data.directPreviewMode) {
      // 复用 goBack：直入预览模式（无外层列表）下，关闭预览 = 返回，
      // 必须走 goBack 的 navigateBack/switchTab/reLaunch 三级兜底
      this.goBack()
      return
    }

    this.setData({ showViewer: false })
  },

  stopPropagation() {},

  onViewerChange(e) {
    const current = Number((e && e.detail && e.detail.current) || 0)
    this.resetViewerGestureState(true)
    this.setData({ currentIndex: current })
  },

  resetViewerGestureState(skipTransition = false) {
    this._gesture = null
    this.setData({
      viewerScale: 1,
      viewerTranslateX: 0,
      viewerTranslateY: 0,
      viewerSwipeY: 0,
      viewerMaskOpacity: 1,
      viewerNavOpacity: 1,
      viewerTransition: !skipTransition,
      viewerDisableSwiper: false
    })
  },

  onViewerTouchStart(e) {
    const touches = e.touches || []
    const now = Date.now()

    if (touches.length === 1) {
      const t = touches[0]
      const isDoubleTap = this._lastTapTime && (now - this._lastTapTime < 280)

      if (isDoubleTap) {
        const nextScale = this.data.viewerScale > 1 ? 1 : 2
        this.setData({
          viewerTransition: true,
          viewerScale: nextScale,
          viewerTranslateX: 0,
          viewerTranslateY: 0,
          viewerSwipeY: 0,
          viewerMaskOpacity: 1,
          viewerNavOpacity: 1,
          viewerDisableSwiper: nextScale > 1
        })
        this._lastTapTime = 0
        return
      }
      this._lastTapTime = now

      this._gesture = {
        type: 'single',
        startX: t.clientX,
        startY: t.clientY,
        baseTranslateX: this.data.viewerTranslateX,
        baseTranslateY: this.data.viewerTranslateY,
        moved: false
      }
      this.setData({ viewerTransition: false })
      return
    }

    if (touches.length === 2) {
      const d = this.getTouchDistance(touches)
      this._gesture = {
        type: 'pinch',
        startDistance: d,
        baseScale: this.data.viewerScale
      }
      this.setData({ viewerTransition: false, viewerDisableSwiper: true })
    }
  },

  onViewerTouchMove(e) {
    if (!this._gesture) return
    const touches = e.touches || []

    if (this._gesture.type === 'pinch' && touches.length === 2) {
      const d = this.getTouchDistance(touches)
      const raw = this._gesture.baseScale * (d / this._gesture.startDistance)
      const nextScale = Math.min(4, Math.max(1, raw))
      this.setData({
        viewerScale: nextScale,
        viewerDisableSwiper: nextScale > 1
      })
      return
    }

    if (this._gesture.type === 'single' && touches.length === 1) {
      const t = touches[0]
      const dx = t.clientX - this._gesture.startX
      const dy = t.clientY - this._gesture.startY
      this._gesture.moved = this._gesture.moved || Math.abs(dx) > 6 || Math.abs(dy) > 6

      if (this.data.viewerScale > 1) {
        this.setData({
          viewerTranslateX: this._gesture.baseTranslateX + dx,
          viewerTranslateY: this._gesture.baseTranslateY + dy,
          viewerDisableSwiper: true
        })
      } else {
        const swipeY = Math.max(0, dy)
        const opacity = Math.max(0.4, 1 - swipeY / SWIPE_MASK_DIVISOR)
        const navOpacity = Math.max(0, 1 - swipeY / SWIPE_NAV_FADE_DISTANCE)
        this.setData({
          viewerSwipeY: swipeY,
          viewerMaskOpacity: opacity,
          viewerNavOpacity: navOpacity,
          viewerDisableSwiper: false
        })
      }
    }
  },

  onViewerTouchEnd() {
    if (!this._gesture) return

    if (this._gesture.type === 'pinch') {
      const fixedScale = Math.min(4, Math.max(1, this.data.viewerScale))
      this.setData({
        viewerTransition: true,
        viewerScale: fixedScale,
        viewerDisableSwiper: fixedScale > 1
      })
      this._gesture = null
      return
    }

    if (this._gesture.type === 'single') {
      if (this.data.viewerScale <= 1) {
        if (this.data.viewerSwipeY > SWIPE_CLOSE_THRESHOLD) {
          this.closeViewer()
        } else {
          this.setData({
            viewerTransition: true,
            viewerSwipeY: 0,
            viewerMaskOpacity: 1,
            viewerNavOpacity: 1,
            viewerTranslateX: 0,
            viewerTranslateY: 0,
            viewerDisableSwiper: false
          })
        }
      } else {
        this.setData({
          viewerTransition: true,
          viewerDisableSwiper: true
        })
      }
    }

    this._gesture = null
  },

  onViewerTouchCancel() {
    this.onViewerTouchEnd()
  },

  getTouchDistance(touches) {
    const x = touches[0].clientX - touches[1].clientX
    const y = touches[0].clientY - touches[1].clientY
    return Math.sqrt(x * x + y * y)
  },

  normalizeImageUrl(url) {
    if (!url) return ''
    const normalized = String(url).replace(/\\/g, '/')
    if (
      normalized.startsWith('http://') ||
      normalized.startsWith('https://') ||
      normalized.startsWith('wxfile://') ||
      normalized.startsWith('cloud://')
    ) {
      return normalized
    }
    return normalized.startsWith('/') ? normalized : `/${normalized}`
  },

  onImageLongPress(e) {
    const imageUrl = e.currentTarget.dataset.url || ''
    if (!imageUrl) return

    this.setData({
      currentImage: imageUrl,
      showActionSheet: true
    })

    wx.showActionSheet({
      itemList: ['保存图片', '转发'],
      success: (res) => {
        this.setData({ showActionSheet: false })

        switch (res.tapIndex) {
          case 0:
            this.saveImage(imageUrl)
            break
          case 1:
            this.shareImage(imageUrl)
            break
        }
      },
      fail: () => {
        this.setData({ showActionSheet: false })
      }
    })
  },

  async saveImage(imageUrl) {
    // 会员门控：灵感流图片保存需要会员
    try {
      const { gateCheck } = require('../../utils/membership.js')
      const allowed = await gateCheck('hd_download', '高清下载')
      if (!allowed) return
    } catch (e) {}

    const app = getApp && getApp()
    if (app && typeof app.ensurePrivacyAuthorized === 'function') {
      const privacyRes = await app.ensurePrivacyAuthorized()
      if (privacyRes && privacyRes.ok === false) {
        wx.showToast({ title: '请先同意隐私指引后再保存图片', icon: 'none' })
        return
      }
    }

    wx.showLoading({
      title: '保存中...',
      mask: true
    })

    if (imageUrl.startsWith('http://') || imageUrl.startsWith('https://')) {
      wx.downloadFile({
        url: imageUrl,
        success: (res) => {
          if (res.statusCode === 200) {
            wx.saveImageToPhotosAlbum({
              filePath: res.tempFilePath,
              success: () => {
                wx.hideLoading()
                wx.showToast({ title: '保存成功', icon: 'success' })
              },
              fail: (err) => {
                wx.hideLoading()
                if (this.isAlbumAuthDeny(err)) {
                  this.promptOpenAlbumSetting('需要授权访问相册后才能保存图片')
                } else {
                  wx.showToast({ title: '保存失败', icon: 'none' })
                }
              }
            })
          }
        },
        fail: () => {
          wx.hideLoading()
          wx.showToast({ title: '下载失败', icon: 'none' })
        }
      })
    } else {
      wx.saveImageToPhotosAlbum({
        filePath: imageUrl,
        success: () => {
          wx.hideLoading()
          wx.showToast({ title: '保存成功', icon: 'success' })
        },
        fail: (err) => {
          wx.hideLoading()
          if (this.isAlbumAuthDeny(err)) {
            this.promptOpenAlbumSetting('需要授权访问相册后才能保存图片')
          } else {
            wx.showToast({ title: '保存失败', icon: 'none' })
          }
        }
      })
    }
  },

  shareImage() {
    wx.showToast({ title: '请使用右上角转发', icon: 'none' })
  },

  isAlbumAuthDeny(err) {
    const errMsg = String((err && err.errMsg) || '')
    return errMsg.includes('auth deny') || errMsg.includes('authorize') || errMsg.includes('auth denied')
  },

  promptOpenAlbumSetting(content) {
    wx.showModal({
      title: '需要相册权限',
      content: content || '请开启相册权限后重试',
      confirmText: '去设置',
      cancelText: '取消',
      success: (res) => {
        if (!res.confirm) return
        wx.openSetting({})
      }
    })
  },

  onShareAppMessage() {
    const imageUrl = this.data.currentImage || (this.data.imageList[0] || '')
    return {
      title: this.data.title,
      path: `/pages/image-preview/image-preview?folder=${encodeURIComponent(this.data.folderPath)}&title=${encodeURIComponent(this.data.title)}`,
      imageUrl
    }
  }
})
